import { Router } from 'express';
import * as taskController from './task.controller.js';
import { protect } from '../../core/middlewares/auth.middleware.js';
import { requirePermission, Permission } from '../../core/middlewares/rbac.middleware.js';
import { validate } from '../../core/middlewares/validate.middleware.js';
import { createTaskSchema, getTasksSchema, taskIdSchema } from './task.schema.js';
const router = Router();
router.use(protect);
router.get('/', validate(getTasksSchema), requirePermission(Permission.READ_TASK), taskController.getTasks);
router.post('/', validate(createTaskSchema), requirePermission(Permission.WRITE_TASK), taskController.createTask);
router.patch('/:id/toggle', validate(taskIdSchema), requirePermission(Permission.WRITE_TASK), taskController.toggleTaskCompletion);
router.delete('/:id', validate(taskIdSchema), requirePermission(Permission.DELETE_TASK), taskController.deleteTask);
export default router;
